INSERT INTO `sms_templates` VALUES (1,'appointment_booking','Appointment Booking Confirmation','Hello [NAME], your appointment at [CLINIC] is confirmed for [DATE] at [TIME] – [REASON].','[\"[NAME]\",\"[DATE]\",\"[TIME]\",\"[REASON]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(2,'appointment_reminder','Appointment Reminder','Hello [NAME], this is a reminder of your appointment at [CLINIC] on [DATE] at [TIME] – [REASON]. Please be on time.','[\"[NAME]\",\"[DATE]\",\"[TIME]\",\"[REASON]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(3,'spectacles_ready','Spectacles Ready for Pickup','Hello [NAME], your spectacles (Order [ORDER_ID]) are ready for collection at [CLINIC]. Please bring this message when you come in.','[\"[NAME]\",\"[ORDER_ID]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(4,'spectacles_reminder','Spectacles Pickup Reminder','Hello [NAME], your spectacles (Order [ORDER_ID]) are still waiting for collection at [CLINIC]. Please come in at your earliest convenience.','[\"[NAME]\",\"[ORDER_ID]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(5,'payment_receipt','Payment Receipt','Hello [NAME], payment of GHS [AMOUNT] received at [CLINIC]. Transaction: [TXN_ID]. Thank you!','[\"[NAME]\",\"[AMOUNT]\",\"[TXN_ID]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(6,'birthday_wishes','Birthday Wishes','Happy Birthday [NAME]! Wishing you good health and clear vision. From all of us at [CLINIC].','[\"[NAME]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(7,'custom_broadcast','Custom Broadcast','Dear [NAME], [CLINIC] wishes you a joyful [OCCASION]! Thank you for trusting us with your eye care.','[\"[NAME]\",\"[CLINIC]\",\"[OCCASION]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(8,'patient_recall','Patient Recall','Hello [NAME], it\'s been a while since your last visit to [CLINIC]. Your eyes deserve regular care — book your next check-up today. Call us anytime!','[\"[NAME]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(9,'appointment_auto_reminder','Appointment Auto-Reminder','Hello [NAME], this is a reminder of your appointment at [CLINIC] tomorrow, [DATE] at [TIME]. Please call us if you need to reschedule.','[\"[NAME]\",\"[CLINIC]\",\"[DATE]\",\"[TIME]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56'),(10,'spectacle_renewal','Spectacle Renewal Reminder','Dear [NAME], your spectacles are due for renewal on [DATE]. Please visit [CLINIC] for your annual eye review.','[\"[NAME]\",\"[DATE]\",\"[CLINIC]\"]','2026-05-22 10:51:56','2026-05-22 10:51:56');
